  },

  _apis: {
    feifan:     'http://ffzy5.tv/api.php/provide/vod',
    wolong:     'https://wolongzyw.com/api.php/provide/vod',
    zuida:      'https://api.zuidapi.com/api.php/provide/vod',
    baiduyun:   'https://api.apibdzy.com/api.php/provide/vod',
    baofeng:    'https://bfzyapi.com/api.php/provide/vod',
    jisu:       'https://jszyapi.com/api.php/provide/vod',
    tianya:     'https://tyyszy.com/api.php/provide/vod',
    wujin:      'https://api.wujinapi.com/api.php/provide/vod',
    modu:       'https://www.mdzyapi.com/api.php/provide/vod',
    sanliuling: 'https://360zy.com/api.php/provide/vod',
    dytt:       'http://caiji.dyttzyapi.com/api.php/provide/vod',
    ruyi:       'https://cj.rycjapi.com/api.php/provide/vod',
    wangwang:   'https://wwzy.tv/api.php/provide/vod',
    hongniu:    'https://www.hongniuzy2.com/api.php/provide/vod',
    guangsu:    'https://api.guangsuapi.com/api.php/provide/vod',
    ikun:       'https://ikunzyapi.com/api.php/provide/vod',
    xinlang:    'https://api.xinlangapi.com/xinlangapi.php/provide/vod',
    lezi:       'https://cj.lziapi.com/api.php/provide/vod',
    jiangyu:    'https://jyzyapi.com/provide/vod',
    yinghua:    'https://m3u8.apiyhzy.com/api.php/provide/vod'
  },

  async search(ctx, { keyword, page, sourceId }) {
    const api = this._apis[sourceId] || this._apis.wolong;
    const data = await ctx.request.getJson(api, {
      query: { ac: 'videolist', wd: keyword, pg: page }
    });
    return {
      list: (data.list || []).map(item => ({
        id: String(item.vod_id),
        title: item.vod_name,
        poster: item.vod_pic || '',
        year: item.vod_year || '',
        desc: item.vod_content || '',
        type_name: item.type_name || '',
        vod_remarks: item.vod_remarks || ''
      })),
      page,
      pageCount: data.pagecount || 1,
      total: data.total || 0
    };
  },

  async recommend(ctx, { page }) {
    const data = await ctx.request.getJson(this._apis.wolong, {
      query: { ac: 'videolist', pg: page || 1 }
    });
    return {
      list: (data.list || []).map(item => ({
        id: String(item.vod_id),
        title: item.vod_name,
        poster: item.vod_pic || '',
        year: item.vod_year || '',
        desc: item.vod_content || ''
      })),
      page: page || 1,
      pageCount: data.pagecount || 1,
      total: data.total || 0
    };
  },

  async detail(ctx, { id, sourceId }) {
    const api = this._apis[sourceId] || this._apis.wolong;
    const data = await ctx.request.getJson(api, {
      query: { ac: 'detail', ids: id }
    });
    const item = (data.list || [])[0];
    if (!item) return { id, title: '', poster: '', year: '', desc: '', playbacks: [] };

    const fromList = (item.vod_play_from || '').split('$$$');
    const urlGroups = (item.vod_play_url || '').split('$$$');

    const playbacks = urlGroups.map((group, i) => {
      const episodes = [];
      const episodes_titles = [];
      (group || '').split('#').forEach(ep => {
        const parts = ep.split('$');
        if (parts.length >= 2 && parts[1]) {
          episodes_titles.push(parts[0]);
          episodes.push(parts[1]);
        }
      });
      return {
        sourceId,
        sourceName: fromList[i] || `线路${i + 1}`,
        episodes,
        episodes_titles
      };
    }).filter(p => p.episodes.length > 0);

    return {
      id,
      title: item.vod_name,
      poster: item.vod_pic || '',
      year: item.vod_year || '',
      desc: item.vod_content || '',
      playbacks
    };
  },

  async resolvePlayUrl(ctx, { playUrl }) {
    return {
      url: playUrl,
      type: 'auto',
      headers: {}
    };
  }
};
